@Composable
fun JobCard(job: JobUi, onOpen: (String) -> Unit, modifier: Modifier = Modifier) {
    Row(modifier.fillMaxWidth().clip(MaterialTheme.shapes.medium).clickable { onOpen(job.id) }.padding(16.dp)) {
        Text(job.title)
    }
}

Modifier.drawWithCache {
    val stroke = Stroke(2.dp.toPx())
    onDrawBehind { drawRoundRect(Color.Gray, style = stroke) }
}
